#include <omp.h>
#include <math.h>

#include "./../main.h"

void kernel_cpu(par_str par,
				dim_str dim,
				box_str* box,
				FOUR_VECTOR* rv,
				fp* qv,
				FOUR_VECTOR* fv)
{
	fp a2 = 2.0 * par.alpha * par.alpha;

	#pragma omp parallel for schedule(static) num_threads(dim.cores_arg)
	for(long bx = 0; bx < dim.number_boxes; bx++) {

		long first_i = box[bx].offset;
		FOUR_VECTOR* rA = &rv[first_i];
		FOUR_VECTOR* fA = &fv[first_i];

		FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
		FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
		fp qB_shared[NUMBER_PAR_PER_BOX];

		for(int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
			rA_shared[i] = rA[i];
		}

		for(int k = 0; k < (1 + box[bx].nn); k++) {

			int pointer;
			if(k == 0) {
				pointer = (int)bx;
			}
			else {
				pointer = box[bx].nei[k - 1].number;
			}

			long first_j = box[pointer].offset;
			FOUR_VECTOR* rB = &rv[first_j];
			fp* qB = &qv[first_j];

			for(int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
				rB_shared[j] = rB[j];
				qB_shared[j] = qB[j];
			}

			for(int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
				for(int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
					fp r2;
					fp u2;
					fp vij;
					fp fs;
					fp fxij;
					fp fyij;
					fp fzij;
					THREE_VECTOR d;

					r2 = rA_shared[i].v + rB_shared[j].v - DOT(rA_shared[i], rB_shared[j]);
					u2 = a2 * r2;
					vij = exp(-u2);
					fs = 2.0 * vij;

					d.x = rA_shared[i].x - rB_shared[j].x;
					fxij = fs * d.x;
					d.y = rA_shared[i].y - rB_shared[j].y;
					fyij = fs * d.y;
					d.z = rA_shared[i].z - rB_shared[j].z;
					fzij = fs * d.z;

					fA[i].v += (double)(qB_shared[j] * vij);
					fA[i].x += (double)(qB_shared[j] * fxij);
					fA[i].y += (double)(qB_shared[j] * fyij);
					fA[i].z += (double)(qB_shared[j] * fzij);
				}
			}
		}
	}
}
